python3 - <<'PY'
import json, urllib.request
metrics = {'requests':0,'tokens':0,'errors':0}
for p in ['What is tool calling?','Risks of agent tools','How to sandbox tools?']:
    data = json.dumps({'model':'gemma3:4b','prompt':p,'stream':False,'options':{'num_predict':15}}).encode()
    req = urllib.request.Request('http://211.170.162.139:10934/api/generate',data=data,headers={'Content-Type':'application/json'})
    try:
        resp = json.loads(urllib.request.urlopen(req).read())
        metrics['requests']+=1
        metrics['tokens']+=resp.get('eval_count',0)
    except Exception:
        metrics['errors']+=1
print('=== Tool Agent Monitoring ===')
for k,v in metrics.items():
    print(f' {k}: {v}')
